export const az900Questions = {
  'cloud-models': [
    { q: 'Which cloud model gives you the MOST control over hardware?', choices: ['IaaS', 'PaaS', 'SaaS', 'Serverless'], answer: 0, explain: 'IaaS gives you virtual hardware — you pick the OS, configure networking, manage storage. Everything above the hypervisor is yours.', traps: { 1: { thought: 'You know PaaS still runs on hardware and thought "platform" means you control the platform.', wrong: 'PaaS abstracts the hardware away. You deploy code, not configure servers. Azure handles the OS, patching, scaling.' }, 2: { thought: 'You confused control with access. You access SaaS apps but control nothing underneath.', wrong: 'SaaS is fully managed. You\'re a user, not an admin. Think Outlook.com — you can\'t touch the mail server.' }, 3: { thought: 'Serverless sounds techy so you assumed it meant more control.', wrong: 'Serverless is LESS control than any other model. You don\'t even see the server. You just upload a function.' } } },
    { q: 'Azure App Service is an example of which model?', choices: ['IaaS', 'PaaS', 'SaaS', 'On-premises'], answer: 1, explain: 'App Service is PaaS — you deploy your code, Azure handles the OS, runtime, scaling, and patching.', traps: { 0: { thought: 'You know App Service runs on VMs somewhere and assumed that makes it IaaS.', wrong: 'The VMs are hidden from you. You never touch the OS. If you can\'t RDP into it, it\'s not IaaS.' }, 2: { thought: 'You thought since it\'s a fully managed service it must be SaaS.', wrong: 'SaaS is for end users (Outlook, Teams). PaaS is for developers deploying their own code. You\'re still writing the app.' }, 3: { thought: 'Nobody picks this one. If you did, re-read the question.', wrong: 'On-premises means your own datacenter. App Service is Azure-hosted.' } } },
    { q: 'Microsoft 365 is an example of which model?', choices: ['IaaS', 'PaaS', 'SaaS', 'Hybrid'], answer: 2, explain: 'M365 (Word, Excel, Outlook online) is SaaS — you use the application as-is. No code, no config, no infrastructure.', traps: { 0: { thought: 'You thought because enterprise companies "run" M365 it must involve infrastructure.', wrong: 'Enterprises subscribe to M365 — they don\'t manage any infrastructure. They just provision user accounts.' }, 1: { thought: 'You thought PaaS because M365 has an API and you can build on it.', wrong: 'Having an API doesn\'t make something PaaS. PaaS means YOU deploy code onto it. M365 is a finished product.' }, 3: { thought: 'You know some companies use M365 alongside on-prem Exchange and called it hybrid.', wrong: 'Hybrid describes infrastructure topology, not a product category. M365 itself is always SaaS.' } } },
    { q: 'In which model does the customer manage the OS?', choices: ['SaaS', 'PaaS', 'IaaS', 'All models'], answer: 2, explain: 'IaaS gives you a VM. You install the OS, patch it, secure it. That\'s the deal — Azure provides virtualized hardware, you do the rest.', traps: { 0: { thought: 'You might have inverted the question and picked the one where Azure manages everything.', wrong: 'SaaS customers don\'t manage anything. Not the OS, not the app, nothing.' }, 1: { thought: 'You know PaaS developers have some config options and confused that with managing the OS.', wrong: 'PaaS config (scaling rules, app settings) is not OS management. You never SSH into an App Service to patch Windows.' }, 3: { thought: 'You thought every cloud customer needs to manage an OS somewhere.', wrong: 'Only IaaS customers manage the OS. That\'s the whole point of PaaS and SaaS — to take that away from you.' } } },
    { q: 'A company wants to run a legacy Windows Server 2012 app in the cloud without modifying it. Which model?', choices: ['SaaS', 'PaaS', 'IaaS', 'Serverless'], answer: 2, explain: 'Lift-and-shift of legacy apps = IaaS. You create a VM, install the old OS, run the old app. No code changes needed.', traps: { 1: { thought: 'You thought PaaS could run anything since it\'s a "platform."', wrong: 'PaaS requires your app to conform to the platform\'s runtime. A legacy Win Server 2012 app won\'t run on App Service without major refactoring.' }, 0: { thought: 'You thought maybe there\'s a SaaS version of old Windows apps.', wrong: 'SaaS means someone else built and hosts the app. Your custom legacy app isn\'t available as SaaS.' }, 3: { thought: 'You thought serverless could run anything.', wrong: 'Serverless runs stateless functions, not full Windows Server applications with specific OS dependencies.' } } },
    { q: 'Which model typically has the LOWEST administrative overhead for the customer?', choices: ['IaaS', 'PaaS', 'On-premises', 'SaaS'], answer: 3, explain: 'SaaS = zero admin. You just use the app. No patching, no scaling, no deployments. That\'s the whole value prop.', traps: { 0: { thought: 'You mixed up "lowest" with "most" and picked the one with the most control.', wrong: 'IaaS has the HIGHEST overhead in the cloud. You manage OS, middleware, runtime, data, and app.' }, 1: { thought: 'PaaS is low overhead so you assumed it was the lowest.', wrong: 'PaaS is low but not the lowest — you still deploy and manage your application code and data.' }, 2: { thought: 'Nobody picks this. On-prem is maximum overhead. Everything is on you.', wrong: 'On-premises is the opposite of low overhead. You own the building, the power, the hardware, everything.' } } },
    { q: 'PaaS eliminates the need for the customer to manage which of the following?', choices: ['Application code', 'User data', 'Operating system and middleware', 'Business logic'], answer: 2, explain: 'PaaS handles OS, middleware, and runtime. You only manage your application code and data.', traps: { 0: { thought: 'You thought PaaS means you don\'t write code at all.', wrong: 'PaaS is FOR developers. You absolutely write and deploy your own code. It just runs on a managed platform.' }, 1: { thought: 'You thought PaaS manages your data for you.', wrong: 'Your data is always your responsibility regardless of cloud model. Azure won\'t manage your database records for you.' }, 3: { thought: 'You assumed "platform" means it handles the business logic too.', wrong: 'Business logic IS your application. PaaS runs it, it doesn\'t write it.' } } },
    { q: 'Which is NOT a characteristic of SaaS?', choices: ['Pay-per-user pricing', 'No infrastructure management', 'Customer controls scaling', 'Accessible via browser'], answer: 2, explain: 'SaaS customers don\'t control scaling — the provider handles everything including capacity. You just use the app.', traps: { 0: { thought: 'You thought pay-per-user is only for some SaaS products.', wrong: 'Pay-per-user is THE typical SaaS pricing model. M365, Salesforce, Slack — all per-user.' }, 1: { thought: 'You thought SaaS might involve some infrastructure work.', wrong: 'Zero infrastructure management is the entire point of SaaS. If you\'re managing infra, it\'s not SaaS.' }, 3: { thought: 'You thought maybe SaaS needs a native app.', wrong: 'Browser accessibility is a hallmark of SaaS. Most SaaS is web-first.' } } },
    { q: 'A startup wants to deploy a Node.js API without managing servers. What should they use?', choices: ['Azure VMs', 'Azure App Service', 'Azure Virtual Desktop', 'Azure Dedicated Host'], answer: 1, explain: 'App Service (PaaS) — deploy Node.js code directly. No server management. Auto-scaling, SSL, CI/CD built in.', traps: { 0: { thought: 'You know VMs can run Node.js and went with the familiar option.', wrong: 'VMs work but the question says "without managing servers." A VM IS a server you manage.' }, 2: { thought: 'You saw "Virtual" and thought it was a cloud server option.', wrong: 'Azure Virtual Desktop is for running Windows desktops in the cloud. It\'s for end-user desktop experiences, not APIs.' }, 3: { thought: 'You thought Dedicated Host sounded premium and appropriate for production.', wrong: 'Dedicated Host is a physical server reserved for your VMs. It\'s MORE management, not less. And way overkill for a startup.' } } },
    { q: 'Which statement is TRUE about cloud service models?', choices: ['SaaS gives more flexibility than IaaS', 'IaaS requires the least management', 'PaaS is ideal for developers who want to focus on code', 'On-premises is a cloud model'], answer: 2, explain: 'PaaS exists specifically so developers can focus on code without worrying about infrastructure. That\'s the pitch.', traps: { 0: { thought: 'You confused flexibility with functionality. SaaS has lots of features but little flexibility.', wrong: 'SaaS is the LEAST flexible. You can\'t change how Outlook works. IaaS is the most flexible — you control everything.' }, 1: { thought: 'You inverted the spectrum. IaaS requires the MOST management in the cloud.', wrong: 'IaaS = you manage OS, middleware, runtime, app, and data. Only the hardware layer is handled by Azure.' }, 3: { thought: 'You thought the question was listing all deployment options including on-prem.', wrong: 'On-premises is NOT a cloud model. It\'s the absence of cloud. The three cloud models are IaaS, PaaS, SaaS.' } } },
  ],

  'shared-responsibility': [
    { q: 'Who is ALWAYS responsible for data and access management, regardless of cloud model?', choices: ['Microsoft', 'The customer', 'Shared between both', 'It depends on the SLA'], answer: 1, explain: 'Your data is always your problem. Even in SaaS — if you share a confidential doc with the wrong person, that\'s on you. Azure can\'t know your data classification.', traps: { 0: { thought: 'You thought since the data is on Azure\'s servers, they must be responsible.', wrong: 'Azure stores your data but has no idea what it means. They can\'t classify it, manage who should see it, or decide retention policies.' }, 2: { thought: 'You thought "shared" was a safe middle-ground answer.', wrong: 'Data responsibility is never shared. Azure provides encryption and tools, but the decisions about data are 100% yours.' }, 3: { thought: 'You thought the SLA would define data responsibilities.', wrong: 'SLAs cover uptime guarantees, not data management responsibilities. Those are in the shared responsibility model.' } } },
    { q: 'Physical security of the datacenter is whose responsibility?', choices: ['Customer', 'Microsoft (always)', 'Shared', 'Depends on the region'], answer: 1, explain: 'Microsoft always secures the physical datacenter — guards, biometrics, cameras, locks. You will never touch Azure\'s hardware.', traps: { 0: { thought: 'You thought dedicated hosts or private clouds might shift physical security to you.', wrong: 'Even with dedicated hosts, the physical server is in Microsoft\'s datacenter. You lease compute, not real estate.' }, 2: { thought: 'You thought maybe the customer needs to do something physical like provide IDs.', wrong: 'You don\'t physically visit Azure datacenters. There\'s nothing physical for you to secure.' }, 3: { thought: 'You thought sovereign regions or government regions might have different rules.', wrong: 'Even in sovereign regions, Microsoft (or the operating partner) handles physical security. The model doesn\'t change per region.' } } },
    { q: 'In IaaS, who manages the operating system?', choices: ['Microsoft', 'The customer', 'Shared equally', 'The OS vendor'], answer: 1, explain: 'IaaS = you get a VM. You pick the OS, you patch it, you secure it, you break it, you fix it.', traps: { 0: { thought: 'You thought Azure would at least keep the OS updated for you.', wrong: 'In IaaS, Azure has no idea what OS you installed or how you configured it. Auto-patching is YOUR opt-in choice.' }, 2: { thought: 'You thought Azure might handle some OS tasks automatically.', wrong: 'In IaaS, the OS is fully your domain. Azure provides the VM, not the OS management.' }, 3: { thought: 'You thought Microsoft or Canonical (Ubuntu) would manage their own OS in the cloud.', wrong: 'The OS vendor provides the image. Once you deploy it, management is 100% on you.' } } },
    { q: 'In SaaS, which of these is the CUSTOMER still responsible for?', choices: ['Patching the application', 'Network infrastructure', 'Accounts and identities they create', 'Server hardening'], answer: 2, explain: 'Even in SaaS, you manage your own accounts. Who has access? What permissions? MFA enabled? That\'s yours.', traps: { 0: { thought: 'You thought maybe enterprise SaaS customers patch their instances.', wrong: 'SaaS patching is the provider\'s job. You use the latest version whether you like it or not. That\'s the SaaS deal.' }, 1: { thought: 'You thought customers need to configure networking for SaaS.', wrong: 'SaaS runs on the provider\'s network. You access it over the internet. No VNet config needed.' }, 3: { thought: 'You thought large organizations might harden their SaaS servers.', wrong: 'You don\'t have servers in SaaS. There\'s nothing to harden. That\'s Microsoft\'s entire value proposition.' } } },
    { q: 'Which layer transitions from customer to Microsoft responsibility as you move from IaaS to SaaS?', choices: ['Physical datacenter', 'Information and data', 'Applications', 'All of the above'], answer: 2, explain: 'Applications shift from customer-managed (IaaS) to provider-managed (SaaS). That\'s the big transition in the middle of the model.', traps: { 0: { thought: 'You thought physical datacenter shifts at some point.', wrong: 'Physical datacenter is ALWAYS Microsoft. It never shifts. It\'s at the bottom of the model and stays blue across all columns.' }, 1: { thought: 'You thought data management shifts to Microsoft in SaaS.', wrong: 'Data is ALWAYS yours. Even in SaaS. Microsoft can\'t decide what\'s confidential in your org.' }, 3: { thought: 'You picked the safe "all of the above" answer.', wrong: 'Only applications transition. Physical DC is always Microsoft, data is always customer. "All of the above" is a trap for people who don\'t know and want to cover their bases.' } } },
    { q: 'Identity and directory infrastructure is whose responsibility in PaaS?', choices: ['Microsoft only', 'Customer only', 'Shared', 'Not applicable'], answer: 2, explain: 'In PaaS, identity infra is shared. Microsoft provides Entra ID as a service. You configure the policies, users, groups, and conditional access rules.', traps: { 0: { thought: 'You thought since Entra ID is a Microsoft service, they handle it all.', wrong: 'Microsoft provides the identity platform. You decide the policies — who can sign in, MFA requirements, conditional access rules.' }, 1: { thought: 'You thought PaaS means you manage everything identity-related.', wrong: 'You don\'t run the identity servers. Microsoft does. But you configure policies and manage user accounts. That\'s shared.' }, 3: { thought: 'You thought identity doesn\'t apply to PaaS.', wrong: 'Every cloud service needs authentication. Identity is always applicable.' } } },
    { q: 'Moving from on-premises to IaaS, which responsibility shifts to Microsoft?', choices: ['Application security', 'Data encryption', 'Physical host maintenance', 'OS patching'], answer: 2, explain: 'The big win of IaaS: you stop worrying about physical hardware. No more replacing drives, managing BIOS, cooling servers. Microsoft does all of that.', traps: { 0: { thought: 'You thought moving to the cloud means Azure secures your apps.', wrong: 'App security is still yours in IaaS. Moving to IaaS doesn\'t magically secure your code.' }, 1: { thought: 'You thought Azure automatically encrypts your data.', wrong: 'Azure provides encryption tools, but in IaaS, configuring encryption is largely your job. Enabling BitLocker on your VMs is on you.' }, 3: { thought: 'You hoped the cloud would handle patching for you.', wrong: 'In IaaS, OS patching is still yours. That\'s the tradeoff for control. If you want Azure to patch, move to PaaS.' } } },
    { q: 'A company using SaaS is breached because an admin shared their password. Who is responsible?', choices: ['Microsoft — they should have prevented it', 'The customer', 'Shared — Microsoft should enforce MFA', 'The SaaS vendor\'s security team'], answer: 1, explain: 'Account management is always the customer\'s responsibility. If your admin shared creds, that\'s your failure, not Microsoft\'s.', traps: { 0: { thought: 'You thought the cloud provider should catch credential sharing.', wrong: 'Microsoft can\'t read minds. If someone gives away a valid password, the login looks legitimate. It\'s not Microsoft\'s job to police your employees.' }, 2: { thought: 'You thought Microsoft should force MFA on everyone.', wrong: 'Microsoft provides MFA tools. Enabling and enforcing them is the customer\'s choice. "Shared" sounds fair but account security decisions are yours.' }, 3: { thought: 'You thought the SaaS vendor has a security team that handles this.', wrong: 'The vendor secures the platform, not your accounts. They can\'t make your admin use a strong password or stop them from writing it on a sticky note.' } } },
  ],

  'regions': [
    { q: 'What is the minimum number of availability zones in a region that supports them?', choices: ['1', '2', '3', '5'], answer: 2, explain: 'Regions with AZ support always have at least 3 zones. Each zone is a physically separate datacenter with independent power, cooling, and networking.', traps: { 0: { thought: 'You thought one AZ = one zone and that\'s enough.', wrong: 'One zone isn\'t fault-tolerant. If it goes down, everything goes down. The point of AZs is redundancy, which requires multiple.' }, 1: { thought: 'You thought two zones would be enough for failover.', wrong: 'Two would technically work for failover but Azure guarantees 3. This allows for maintenance on one zone while still having redundancy.' }, 3: { thought: 'You might have confused AZs with the number of datacenters Azure has in a region.', wrong: 'A region might have many datacenters, but AZs group them into exactly 3+ logical zones.' } } },
    { q: 'Region pairs are used primarily for...', choices: ['Lower cost by sharing resources', 'Disaster recovery and business continuity', 'Faster compute performance', 'Load balancing user traffic'], answer: 1, explain: 'Region pairs exist for DR. If an entire region goes down (natural disaster, major outage), your data fails over to the paired region. They\'re always in the same geography for data residency.', traps: { 0: { thought: 'You thought pairing regions somehow shares costs.', wrong: 'Paired regions don\'t share pricing. You pay for resources in each region independently.' }, 2: { thought: 'You thought paired regions work together to boost performance.', wrong: 'Performance comes from choosing a region close to your users. Pairs are geographically separated on purpose — that\'s for DR, not speed.' }, 3: { thought: 'You confused region pairs with Azure Load Balancer or Traffic Manager.', wrong: 'Load balancing is a networking feature. Region pairs are a DR feature. Different purpose entirely.' } } },
    { q: 'Azure Government is an example of a...', choices: ['Region pair', 'Sovereign region', 'Availability zone', 'Management group'], answer: 1, explain: 'Sovereign regions are physically and logically isolated from the main Azure network. Azure Government serves US government agencies. Azure China (21Vianet) is another example.', traps: { 0: { thought: 'You thought Government regions are paired with regular regions.', wrong: 'Sovereign regions pair with OTHER sovereign regions, not with commercial Azure. They\'re completely isolated networks.' }, 2: { thought: 'You confused the concept of an isolated zone with an isolated region.', wrong: 'AZs are isolated datacenters WITHIN a region. Sovereign regions are entire isolated cloud instances.' }, 3: { thought: 'You thought it was an organizational concept like management groups.', wrong: 'Management groups organize subscriptions. Sovereign regions are physical infrastructure isolation.' } } },
    { q: 'A company must keep all data within Germany due to regulations. What Azure feature addresses this?', choices: ['Availability Zones', 'Resource Groups', 'Geographies and data residency', 'Azure Policy'], answer: 2, explain: 'Azure Geographies contain one or more regions within a regulatory boundary. German regions keep data in Germany. Region pairs within a geography ensure DR doesn\'t violate data residency.', traps: { 0: { thought: 'You thought AZs within German regions solve data residency.', wrong: 'AZs provide fault tolerance, not data residency guarantees. AZs are within one region — they don\'t address cross-border concerns.' }, 1: { thought: 'You thought organizing resources into groups controls where data lives.', wrong: 'Resource groups are logical containers. They don\'t control the physical location of data. A resource group in "East US" could contain resources in any region.' }, 3: { thought: 'You thought Azure Policy could restrict data to Germany.', wrong: 'Azure Policy CAN restrict which regions you deploy to, but the feature that guarantees data stays in a country is the geography/region architecture itself. Policy is enforcement, not the mechanism.' } } },
    { q: 'If Region A goes down, updates to Region A\'s pair (Region B) are...', choices: ['Deployed first', 'Delayed until Region A recovers', 'Deployed normally', 'Cancelled'], answer: 1, explain: 'Azure deliberately staggers updates across paired regions. If one region is down, its pair won\'t get updated simultaneously. This prevents both regions from failing at once due to a bad update.', traps: { 0: { thought: 'You thought paired regions get priority treatment.', wrong: 'The pair gets DELAYED treatment, not priority. The whole point is to avoid updating both at the same time.' }, 2: { thought: 'You thought Azure would just proceed with normal updates regardless.', wrong: 'If both regions got the same bad update, your DR strategy is useless. Azure sequences updates across pairs specifically to prevent this.' }, 3: { thought: 'You thought Azure would halt all operations during an outage.', wrong: 'Updates continue — just not to the paired region simultaneously. Azure doesn\'t stop everything, it staggers.' } } },
    { q: 'Which is TRUE about Availability Zones?', choices: ['Every Azure region has them', 'They protect against datacenter-level failures', 'They eliminate the need for backups', 'They\'re free to use'], answer: 1, explain: 'Each AZ is a separate datacenter. If one catches fire, your app in another AZ keeps running. That\'s datacenter-level fault tolerance.', traps: { 0: { thought: 'You assumed all regions are equal and all have AZs.', wrong: 'Not all regions support AZs. Smaller or older regions may only have a single datacenter. Check the docs before architecting.' }, 2: { thought: 'You thought AZ redundancy means you don\'t need backups.', wrong: 'AZs protect against physical failures. They don\'t protect against accidental deletion, ransomware, or data corruption. You still need backups.' }, 3: { thought: 'You thought AZs are just a configuration option with no cost.', wrong: 'Deploying across AZs can increase costs — cross-zone data transfer is billed, and zone-redundant services may cost more.' } } },
    { q: 'How many region pairs does each region have?', choices: ['None — pairing is optional', 'Exactly one', 'Two or more', 'It varies by subscription'], answer: 1, explain: 'Each region is paired with exactly one other region in the same geography. It\'s a 1:1 relationship.', traps: { 0: { thought: 'You thought pairing was something you configure yourself.', wrong: 'Region pairs are defined by Microsoft, not by you. You can\'t choose or change your pair.' }, 2: { thought: 'You thought a region might pair with multiple regions for extra safety.', wrong: 'It\'s strictly 1:1. East US pairs with West US. Not with Central US too. One pair per region.' }, 3: { thought: 'You thought maybe premium subscriptions get more pairs.', wrong: 'Region pairs are infrastructure-level, not subscription-level. Every customer gets the same pair.' } } },
  ],

  'resource-hierarchy': [
    { q: 'What is the TOP level of the Azure resource hierarchy?', choices: ['Subscription', 'Root Management Group', 'Resource Group', 'Tenant'], answer: 1, explain: 'Root Management Group sits at the top. Every tenant has one automatically. All subscriptions and management groups live under it.', traps: { 0: { thought: 'You work with subscriptions daily and thought they\'re the top.', wrong: 'Subscriptions sit UNDER management groups. They\'re the billing boundary, not the organizational top.' }, 2: { thought: 'You thought resource groups contain everything.', wrong: 'Resource groups contain resources. They sit inside subscriptions, which sit inside management groups.' }, 3: { thought: 'You thought the Entra ID tenant is the top of the hierarchy.', wrong: 'The tenant is the identity boundary, not part of the resource management hierarchy. The root management group is associated with the tenant but they\'re different concepts.' } } },
    { q: 'A resource can belong to how many resource groups?', choices: ['Exactly one', 'Up to 5', 'Unlimited', 'One per subscription'], answer: 0, explain: 'Strictly one. A resource lives in exactly one resource group. Period. Move it or delete it, but it can\'t straddle two groups.', traps: { 1: { thought: 'You thought Azure might allow some flexibility like tagging.', wrong: 'Tags are many-to-many. Resource group membership is 1:1. Don\'t confuse them.' }, 2: { thought: 'You thought resources could be shared across groups.', wrong: 'Resources in different groups can TALK to each other, but each resource has exactly one home group.' }, 3: { thought: 'You thought maybe it\'s one group per subscription but can span subscriptions.', wrong: 'A resource can\'t span subscriptions. It belongs to one resource group in one subscription.' } } },
    { q: 'Which can contain multiple subscriptions?', choices: ['Resource Group', 'Management Group', 'Resource', 'Availability Zone'], answer: 1, explain: 'Management Groups are organizational containers for subscriptions. One MG can hold many subscriptions, and MGs can nest up to 6 levels.', traps: { 0: { thought: 'You thought resource groups are higher-level containers.', wrong: 'Resource groups sit INSIDE subscriptions. They can\'t contain subscriptions — that\'s backwards.' }, 2: { thought: 'You confused resource with resource group.', wrong: 'A resource is a single service instance (one VM, one database). It can\'t contain anything.' }, 3: { thought: 'You guessed from the name that AZs might organize subscriptions.', wrong: 'AZs are physical datacenter zones. They have nothing to do with organizational hierarchy.' } } },
    { q: 'What happens when you delete a resource group?', choices: ['Resources inside are moved to a default group', 'All resources inside are deleted', 'Only empty resources are deleted', 'You get a warning but nothing happens'], answer: 1, explain: 'Deleting a resource group deletes EVERYTHING inside it. VMs, databases, storage — all gone. This is why resource locks exist.', traps: { 0: { thought: 'You thought Azure would be nice and save your stuff somewhere.', wrong: 'Azure doesn\'t relocate resources. Delete the group, lose the resources. No safety net unless you set up locks or backups.' }, 2: { thought: 'You thought Azure would only delete resources that aren\'t in use.', wrong: 'Azure doesn\'t check if resources are "in use." It deletes everything in the group unconditionally.' }, 3: { thought: 'You thought Azure would protect you from yourself.', wrong: 'Azure warns you in the portal, but once you confirm, it\'s done. That\'s why governance tools like resource locks are critical.' } } },
    { q: 'Management groups can be nested up to how many levels?', choices: ['3 levels', '6 levels', '10 levels', 'Unlimited'], answer: 1, explain: '6 levels of depth (not including the root management group). This is enough for most enterprise org structures.', traps: { 0: { thought: 'You made a conservative guess.', wrong: '3 levels would be too limiting for large enterprises with complex organizational structures.' }, 2: { thought: 'You assumed Azure would allow more nesting for big orgs.', wrong: '10 is too many. Microsoft caps it at 6 to prevent overly complex hierarchies that become unmanageable.' }, 3: { thought: 'You thought Azure wouldn\'t impose a limit.', wrong: 'Azure limits nesting to 6 levels. Unlimited nesting would create unmanageable policy inheritance chains.' } } },
    { q: 'Policies applied at the management group level...', choices: ['Only affect that management group', 'Are inherited by all child subscriptions and resource groups', 'Must be reapplied at each level', 'Can be overridden by child subscriptions'], answer: 1, explain: 'Policies flow downward. Apply a policy at the MG level and every subscription, resource group, and resource under it inherits it. That\'s the power of the hierarchy.', traps: { 0: { thought: 'You thought policies are scoped only to where you apply them.', wrong: 'The whole point of hierarchy is inheritance. If policies didn\'t flow down, management groups would be useless.' }, 2: { thought: 'You thought each level needs its own policy assignment.', wrong: 'You CAN apply policies at each level, but you don\'t HAVE to. Parent policies automatically cascade.' }, 3: { thought: 'You thought child subscriptions could opt out of parent policies.', wrong: 'Child resources CANNOT override parent policies. The parent wins. This is by design — it prevents rogue subscriptions from ignoring corporate governance.' } } },
  ],

  'compute': [
    { q: 'Which compute option runs code ONLY when triggered and has no idle cost?', choices: ['Virtual Machines', 'Azure Kubernetes Service', 'Azure Functions', 'Azure App Service'], answer: 2, explain: 'Azure Functions (serverless) are event-driven. No trigger = no execution = no cost. You pay per execution and compute time only.', traps: { 0: { thought: 'You thought VMs can be stopped to avoid cost.', wrong: 'Stopped VMs still incur storage costs. And a "stopped" VM isn\'t event-triggered — it\'s just turned off. Functions are fundamentally different.' }, 1: { thought: 'You thought AKS can scale to zero.', wrong: 'AKS can scale pods to zero but the node pool still runs and costs money. The control plane also has costs.' }, 3: { thought: 'You thought App Service on a free tier has no cost.', wrong: 'The question says "runs code ONLY when triggered." App Service runs continuously whether traffic hits it or not. Even the free tier reserves compute.' } } },
    { q: 'Which service is best for lift-and-shift migrations?', choices: ['Azure Functions', 'Virtual Machines', 'App Service', 'Logic Apps'], answer: 1, explain: 'Lift-and-shift = move the app as-is without rewriting. VMs replicate your on-prem server in the cloud. Same OS, same config, same app.', traps: { 0: { thought: 'You thought "shifting" to the cloud means modernizing to serverless.', wrong: 'Lift-and-shift specifically means NO modernization. You take the existing app and run it on cloud infrastructure. Functions would require a complete rewrite.' }, 2: { thought: 'You thought App Service could run any legacy app.', wrong: 'App Service requires your app to be a web app compatible with its runtime. A legacy Windows service or desktop app won\'t work on App Service.' }, 3: { thought: 'You confused Logic Apps with general app hosting.', wrong: 'Logic Apps are workflow automation (like IFTTT). They don\'t host applications.' } } },
    { q: 'AKS is used for orchestrating...', choices: ['Virtual Machines', 'Containers', 'Serverless Functions', 'SQL Databases'], answer: 1, explain: 'AKS = Azure Kubernetes Service. Kubernetes orchestrates containers — scheduling, scaling, healing, networking them across a cluster.', traps: { 0: { thought: 'You thought Kubernetes manages VMs since containers run on VMs.', wrong: 'Kubernetes manages containers, not the VMs they run on. AKS handles the underlying VMs for you.' }, 2: { thought: 'You confused containers with serverless.', wrong: 'Containers and serverless are different paradigms. Containers package apps with their dependencies. Functions are single-purpose code snippets.' }, 3: { thought: 'You associated "service" with database services.', wrong: 'AKS has nothing to do with databases. The K stands for Kubernetes.' } } },
    { q: 'Which Azure compute service would you use to run containers WITHOUT managing the underlying infrastructure?', choices: ['Azure VMs with Docker', 'Azure Container Instances', 'Azure Dedicated Host', 'Azure Batch'], answer: 1, explain: 'ACI = containers without infrastructure. No VMs to manage, no clusters to configure. Just give it a container image and it runs.', traps: { 0: { thought: 'You know Docker runs on VMs and went with the familiar option.', wrong: 'The question says "WITHOUT managing infrastructure." A VM with Docker means you\'re managing the VM — OS patches, sizing, networking.' }, 2: { thought: 'You thought Dedicated Host provides a clean hosting environment.', wrong: 'Dedicated Host is a PHYSICAL server reserved for your VMs. It\'s MORE infrastructure management, not less.' }, 3: { thought: 'You thought Batch runs container workloads.', wrong: 'Azure Batch is for large-scale parallel computing jobs, not general container hosting.' } } },
    { q: 'Azure Virtual Machine Scale Sets (VMSS) provide which capability?', choices: ['Automatic OS patching', 'Auto-scaling groups of identical VMs', 'Converting VMs to containers', 'Serverless VM execution'], answer: 1, explain: 'VMSS creates and manages a group of identical, load-balanced VMs. It auto-scales based on demand or a schedule.', traps: { 0: { thought: 'You thought Scale Sets handle patching because they manage VMs.', wrong: 'VMSS can be configured for auto-patching but that\'s not its primary capability. It\'s about scaling identical VMs.' }, 2: { thought: 'You thought "scale" might mean scaling from VMs to containers.', wrong: 'VMSS stays in VM territory. It doesn\'t convert anything to containers.' }, 3: { thought: 'You thought the "virtual" and "scale" combination implies serverless.', wrong: 'VMs are the opposite of serverless. You\'re explicitly managing server instances. VMSS just manages many of them.' } } },
    { q: 'Which is the most cost-effective for unpredictable, spiky traffic?', choices: ['Reserved VMs', 'Azure Functions consumption plan', 'Dedicated Host', 'App Service fixed plan'], answer: 1, explain: 'Consumption plan = pay only when code runs. Spiky traffic means long idle periods. Why pay for idle servers when Functions charges zero during idle?', traps: { 0: { thought: 'You thought reserved instances are always cheapest.', wrong: 'Reserved VMs are cheap per-hour but you pay whether traffic spikes or not. For spiky/unpredictable traffic, you\'re paying for idle capacity.' }, 2: { thought: 'You thought dedicated hardware handles spikes better.', wrong: 'Dedicated Host is the most expensive option. You\'re paying for an entire physical server 24/7 regardless of traffic.' }, 3: { thought: 'You thought App Service is cost-effective for web traffic.', wrong: 'A fixed App Service plan runs constantly. For spiky traffic with long idle periods, you\'re wasting money during the quiet times.' } } },
  ],

  'networking': [
    { q: 'NSG rules filter traffic based on...', choices: ['Cost thresholds', 'IP address, port, and protocol', 'Azure region only', 'User identity'], answer: 1, explain: 'NSG rules evaluate: source/destination IP, port number, and protocol (TCP/UDP). That\'s it. Simple packet filtering.', traps: { 0: { thought: 'You confused Network Security Groups with Cost Management budgets.', wrong: 'NSGs are firewalls. They filter network packets, not costs.' }, 2: { thought: 'You thought NSGs work at the region level.', wrong: 'NSGs work at the subnet or NIC level within a VNet. They filter individual packets, not entire region traffic.' }, 3: { thought: 'You thought NSGs could use identity-based rules.', wrong: 'NSGs work at Layer 3/4 (IP/port). They don\'t know who the user is. For identity-based access, use Conditional Access or Azure Firewall Premium.' } } },
    { q: 'ExpressRoute provides what kind of connection?', choices: ['Public internet VPN with encryption', 'Private dedicated fiber connection', 'Free VPN tunnel', 'Wireless connection to Azure'], answer: 1, explain: 'ExpressRoute is a private, dedicated connection from your on-prem network to Azure. It doesn\'t touch the public internet. Provided by connectivity partners (ISPs).', traps: { 0: { thought: 'You confused ExpressRoute with VPN Gateway. Both connect on-prem to Azure.', wrong: 'VPN Gateway goes over the public internet (encrypted). ExpressRoute uses a private circuit — no public internet at all. Different infrastructure.' }, 2: { thought: 'You thought Azure offers free tunnels.', wrong: 'ExpressRoute is one of the most expensive networking services. You pay Azure AND the connectivity provider. It\'s enterprise-grade.' }, 3: { thought: 'You thought "express" meant fast wireless.', wrong: 'ExpressRoute is physical fiber optic cable. Nothing wireless about it.' } } },
    { q: 'A VNet is scoped to a single...', choices: ['Subscription', 'Region', 'Resource group', 'Availability zone'], answer: 1, explain: 'A VNet lives in one region. It cannot span regions. To connect VNets in different regions, you use VNet peering or VPN gateways.', traps: { 0: { thought: 'You thought VNets are subscription-level resources.', wrong: 'VNets exist in a subscription but they\'re scoped to a region. You can have multiple VNets per subscription, each in different regions.' }, 2: { thought: 'You thought VNets are contained by resource groups.', wrong: 'A VNet is IN a resource group for management purposes, but its scope is the region. The RG is just organizational.' }, 3: { thought: 'You thought networks are per availability zone.', wrong: 'VNets span ALL availability zones within a region. That\'s how resources in different AZs communicate.' } } },
    { q: 'Which service provides DNS-based traffic routing to the nearest healthy endpoint?', choices: ['Azure Load Balancer', 'Azure Traffic Manager', 'NSG', 'VNet Peering'], answer: 1, explain: 'Traffic Manager uses DNS to route users to the closest or healthiest endpoint globally. It\'s a global traffic routing service.', traps: { 0: { thought: 'You thought Load Balancer handles all traffic routing.', wrong: 'Azure Load Balancer works at Layer 4 within a region. It doesn\'t do DNS-based or global routing. That\'s Traffic Manager\'s job.' }, 2: { thought: 'You thought NSGs direct traffic.', wrong: 'NSGs FILTER traffic (allow/deny). They don\'t ROUTE it anywhere.' }, 3: { thought: 'You thought peering routes traffic between regions.', wrong: 'VNet peering connects two VNets. It doesn\'t do health-based routing or DNS resolution.' } } },
    { q: 'VNet peering allows...', choices: ['VNets to share the same IP address space', 'Resources in different VNets to communicate privately', 'VNets to merge into one', 'Free cross-region data transfer'], answer: 1, explain: 'Peering connects two VNets over Microsoft\'s backbone. Resources communicate as if on the same network, but the VNets stay separate.', traps: { 0: { thought: 'You thought peering merges the address spaces.', wrong: 'Peered VNets must have NON-overlapping IP ranges. They stay separate — peering just creates a connection.' }, 2: { thought: 'You thought peering combines VNets.', wrong: 'VNets never merge. Peering is a link, not a union. Each VNet keeps its own configuration.' }, 3: { thought: 'You thought peering means free data transfer.', wrong: 'Cross-region peering incurs data transfer charges. Even same-region peering has small ingress/egress costs.' } } },
    { q: 'Azure Firewall vs NSG — which statement is correct?', choices: ['NSG replaces Azure Firewall', 'Azure Firewall is Layer 7 and NSG is Layer 3/4', 'They are identical services', 'NSG is more expensive'], answer: 1, explain: 'Azure Firewall operates at Layer 7 (application) — it can inspect FQDN, URLs, and application protocols. NSGs are Layer 3/4 — IP addresses and ports only.', traps: { 0: { thought: 'You thought NSGs can do everything a firewall does.', wrong: 'NSGs are basic packet filters. They can\'t inspect URLs, do TLS termination, or filter by domain name. Azure Firewall can.' }, 2: { thought: 'You thought they\'re the same thing with different names.', wrong: 'Completely different services. NSG = simple rules on subnets/NICs. Azure Firewall = centralized, stateful, Layer 7 inspection.' }, 3: { thought: 'You assumed the more granular service costs more.', wrong: 'Azure Firewall is significantly more expensive than NSGs (which are free). But the question asks which statement is correct, not which costs more.' } } },
  ],

  'storage': [
    { q: 'Which storage is best for unstructured data like images and videos?', choices: ['Table Storage', 'Queue Storage', 'Blob Storage', 'Azure SQL'], answer: 2, explain: 'Blob = Binary Large Object. It\'s Azure\'s object storage for unstructured data — images, videos, backups, logs, anything that isn\'t rows and columns.', traps: { 0: { thought: 'You thought Table Storage stores any kind of data.', wrong: 'Table Storage is for structured NoSQL data (key-value pairs). Images aren\'t key-value pairs.' }, 1: { thought: 'You confused storage types. Queue is for messages.', wrong: 'Queue Storage holds small messages between app components. It\'s not for storing files.' }, 3: { thought: 'You thought a database could store images.', wrong: 'Technically yes, but it\'s a terrible idea for large binary files. Blob storage is purpose-built for this and orders of magnitude cheaper.' } } },
    { q: 'GRS replicates data to...', choices: ['The same datacenter (3 copies)', 'A paired region (6 total copies)', 'All Azure regions', 'The nearest availability zone'], answer: 1, explain: 'GRS = Geo-Redundant Storage. 3 copies locally (LRS) + 3 copies in the paired region = 6 total. Survives regional disasters.', traps: { 0: { thought: 'You described LRS, not GRS. LRS is 3 copies in one datacenter.', wrong: 'GRS adds the "Geo" part. The whole point is replication to another region. 3 local copies is just LRS.' }, 2: { thought: 'You thought geo-redundant means globally distributed.', wrong: 'GRS goes to ONE paired region, not all regions. Putting data in every region would be astronomically expensive.' }, 3: { thought: 'You confused GRS with ZRS. ZRS spreads across availability zones.', wrong: 'ZRS = 3 copies across 3 AZs in the same region. GRS = 3 copies locally + 3 in another region. Different strategies.' } } },
    { q: 'Azure Files supports which protocol?', choices: ['HTTP only', 'SMB and NFS', 'FTP', 'SFTP only'], answer: 1, explain: 'Azure Files supports SMB (Server Message Block) and NFS (Network File System). You can mount file shares directly on Windows, Linux, and macOS.', traps: { 0: { thought: 'You thought cloud storage is all REST/HTTP.', wrong: 'That\'s Blob Storage. Azure Files specifically supports file-sharing protocols because it\'s meant to replace on-prem file servers.' }, 2: { thought: 'You defaulted to the oldest file transfer protocol you know.', wrong: 'FTP is ancient and insecure. Azure Files uses modern file-sharing protocols. Azure does support SFTP on Blob Storage, but Files uses SMB/NFS.' }, 3: { thought: 'You knew SFTP is supported somewhere in Azure and guessed.', wrong: 'SFTP is available on Azure Blob Storage (as a feature), not Azure Files. Files uses SMB and NFS.' } } },
    { q: 'Which storage tier should you use for data accessed less than once a year?', choices: ['Hot tier', 'Cool tier', 'Archive tier', 'Premium tier'], answer: 2, explain: 'Archive tier has the lowest storage cost but highest access cost and retrieval delay (hours). Perfect for data you must keep but rarely touch.', traps: { 0: { thought: 'You thought hot is the default and works for everything.', wrong: 'Hot has the highest storage cost. For rarely-accessed data, you\'re wasting money keeping it in hot.' }, 1: { thought: 'You thought cool tier covers infrequent access.', wrong: 'Cool is for data accessed less than once per month. Less than once per YEAR is archive territory. Cool would still be overpaying.' }, 3: { thought: 'You thought premium means it handles everything best.', wrong: 'Premium is for high-performance, low-latency workloads. It\'s the MOST expensive tier — opposite of what you want for cold data.' } } },
    { q: 'What is the durability of Azure Storage with LRS?', choices: ['99%', '99.9%', '99.999999999% (11 nines)', '99.99%'], answer: 2, explain: 'Even basic LRS provides 11 nines of durability. That\'s 99.999999999%. Your data is extremely unlikely to be lost even with the cheapest redundancy.', traps: { 0: { thought: 'You thought the cheapest option would have low durability.', wrong: '11 nines means you\'d lose 1 object out of 100 billion. LRS is cheap but still incredibly durable. Azure doesn\'t sell unreliable storage.' }, 1: { thought: 'You confused durability with availability/SLA.', wrong: 'Durability (will my data survive?) and availability (can I access it right now?) are different metrics. LRS availability SLA is 99.9%, but durability is 11 nines.' }, 3: { thought: 'You knew 99.99% SLA numbers from other services and applied it here.', wrong: '99.99% is a common SLA number but durability is measured differently — it\'s always much higher than availability.' } } },
    { q: 'Which storage redundancy option is CHEAPEST?', choices: ['ZRS', 'GRS', 'LRS', 'GZRS'], answer: 2, explain: 'LRS (Locally Redundant Storage) = 3 copies in one datacenter. Cheapest because all copies are in the same physical location.', traps: { 0: { thought: 'You thought spreading across zones would somehow be cheaper.', wrong: 'More locations = more infrastructure = more cost. ZRS uses 3 AZs, each with different power/network. That costs more than one datacenter.' }, 1: { thought: 'You thought geo-redundancy might have volume discounts.', wrong: 'GRS replicates to an entire second region. That\'s roughly double the storage cost of LRS.' }, 3: { thought: 'You thought the longest acronym means the best value.', wrong: 'GZRS is the MOST expensive option — zone-redundant locally AND geo-replicated. Maximum protection, maximum cost.' } } },
  ],

  'identity': [
    { q: 'Microsoft Entra ID is the new name for...', choices: ['Azure Active Directory', 'Active Directory Domain Services', 'Azure Key Vault', 'Microsoft Defender'], answer: 0, explain: 'Azure AD was renamed to Microsoft Entra ID in 2023. Same cloud identity service, new brand. On-prem AD DS is a different product entirely.', traps: { 1: { thought: 'You know Active Directory and thought it\'s the same thing.', wrong: 'AD DS is on-premises directory services (domain controllers, Group Policy, LDAP). Entra ID is cloud-native identity (OAuth, SAML, OpenID Connect). Different architectures.' }, 2: { thought: 'You associated identity with secrets management.', wrong: 'Key Vault stores secrets, keys, and certificates. It doesn\'t manage user identities or authentication.' }, 3: { thought: 'You confused identity with security products.', wrong: 'Defender is a security product line (threat detection, antivirus). Entra ID is identity and access management.' } } },
    { q: 'MFA requires at least how many verification methods?', choices: ['1', '2', '3', '4'], answer: 1, explain: 'Multi-Factor Authentication = at least 2 factors from different categories: something you know (password) + something you have (phone) or something you are (biometric).', traps: { 0: { thought: 'You thought a strong password alone counts as MFA.', wrong: 'The "multi" in MFA means more than one. A single factor, no matter how strong, is just regular authentication.' }, 2: { thought: 'You thought MFA requires all three factor categories.', wrong: 'MFA requires at least 2 factors. Using all 3 categories is stronger but not required. Password + phone approval = valid MFA.' }, 3: { thought: 'You thought you need a password, phone, biometric, AND a security key.', wrong: 'That would be great security but MFA only requires 2 factors minimum. Most implementations use password + authenticator app.' } } },
    { q: 'Conditional Access policies can block access based on...', choices: ['Time of day only', 'Location, device state, risk level, and more', 'Username only', 'Password strength only'], answer: 1, explain: 'Conditional Access evaluates signals: user location, device compliance, sign-in risk, application sensitivity, and more. It\'s if/then logic for access decisions.', traps: { 0: { thought: 'You thought Conditional Access is just a schedule-based restriction.', wrong: 'Time of day can be a factor but it\'s just one of many signals. Conditional Access is much broader.' }, 2: { thought: 'You thought it only looks at who you are.', wrong: 'Conditional Access goes way beyond identity. It considers WHERE you are, WHAT device you\'re using, HOW risky the sign-in looks.' }, 3: { thought: 'You thought it evaluates password quality.', wrong: 'Password policies are separate. Conditional Access doesn\'t check your password — it checks everything AROUND the sign-in attempt.' } } },
    { q: 'What is Single Sign-On (SSO)?', choices: ['Using one password for one app', 'Signing in once to access multiple applications', 'Signing in separately to each application', 'Two-factor authentication'], answer: 1, explain: 'SSO = one login grants you access to multiple apps within the same identity provider. Sign into Entra ID once, access M365, Salesforce, ServiceNow — no re-entering passwords.', traps: { 0: { thought: 'You focused on "single" and thought it meant one app.', wrong: 'The "single" refers to the sign-on action, not the number of apps. One sign-on, many apps.' }, 2: { thought: 'You confused the opposite behavior with SSO.', wrong: 'Signing into each app separately is the PROBLEM SSO solves. Without SSO, users have different passwords for every app.' }, 3: { thought: 'You confused SSO with MFA.', wrong: 'SSO reduces the number of times you authenticate. MFA increases the strength of each authentication. They complement each other but are different concepts.' } } },
    { q: 'Which is TRUE about Microsoft Entra ID vs on-premises Active Directory?', choices: ['They are the same product', 'Entra ID uses OAuth/SAML; on-prem AD uses Kerberos/LDAP', 'On-prem AD is being discontinued', 'Entra ID requires domain controllers'], answer: 1, explain: 'Different architectures, different protocols. Entra ID is cloud-native (REST APIs, OAuth 2.0, SAML, OpenID Connect). On-prem AD is traditional (LDAP, Kerberos, NTLM, Group Policy).', traps: { 0: { thought: 'You thought the rename meant they merged the products.', wrong: 'Azure AD was renamed to Entra ID. On-prem AD DS was not renamed or merged. They remain separate products with different protocols.' }, 2: { thought: 'You assumed Microsoft would phase out the old product.', wrong: 'On-prem AD DS is still fully supported and widely used. Most enterprises run both (hybrid identity with AD Connect).' }, 3: { thought: 'You assumed cloud identity still needs traditional infrastructure.', wrong: 'Entra ID has no domain controllers. It\'s a fully managed SaaS identity service. No servers to manage.' } } },
    { q: 'Passwordless authentication includes which of the following?', choices: ['Longer passwords', 'FIDO2 security keys, Windows Hello, Authenticator app', 'Removing all authentication', 'SMS codes only'], answer: 1, explain: 'Passwordless means replacing passwords with stronger, phishing-resistant methods. FIDO2 keys, biometrics (Windows Hello), and the Authenticator app\'s push notifications.', traps: { 0: { thought: 'You thought "passwordless" was about making passwords better.', wrong: 'Passwordless means NO password at all. Not longer passwords, not better passwords — zero passwords.' }, 2: { thought: 'You thought passwordless means no authentication.', wrong: 'Passwordless doesn\'t mean unauthenticated. You still prove your identity — just not with a password. A fingerprint or hardware key replaces it.' }, 3: { thought: 'You thought SMS verification counts as passwordless.', wrong: 'SMS is a second factor, not a replacement for passwords. It\'s also considered weak because of SIM-swapping attacks. FIDO2 and biometrics are the real passwordless methods.' } } },
  ],

  'rbac': [
    { q: 'RBAC roles can be assigned at which level?', choices: ['Resource group only', 'Management group, subscription, resource group, or resource', 'Subscription only', 'Tenant level only'], answer: 1, explain: 'RBAC supports all 4 levels of the resource hierarchy. Assign at the scope that makes sense — roles inherit downward.', traps: { 0: { thought: 'You work mostly with resource groups and thought that\'s the only scope.', wrong: 'RG is the most common scope but not the only one. You can assign roles as broadly as a management group or as narrowly as a single resource.' }, 2: { thought: 'You thought subscriptions are the billing and access boundary.', wrong: 'Subscriptions are ONE scope. RBAC is more flexible — you can go broader (MG) or narrower (RG, resource).' }, 3: { thought: 'You confused RBAC scope with Entra ID tenant-level roles.', wrong: 'Entra ID roles (Global Admin, User Admin) are tenant-level. Azure RBAC roles (Owner, Contributor, Reader) work across the resource hierarchy.' } } },
    { q: 'The principle of least privilege means...', choices: ['Give everyone Owner role for convenience', 'Grant only the permissions needed to do the job', 'Deny all access by default forever', 'Use the same role for everyone'], answer: 1, explain: 'Least privilege: give the minimum permissions required. A developer who only needs to read logs shouldn\'t have Owner on the subscription.', traps: { 0: { thought: 'You thought convenience matters more than security in practice.', wrong: 'Giving everyone Owner is the #1 RBAC anti-pattern. One compromised account with Owner = total access to everything.' }, 2: { thought: 'You took the "least" too literally and thought it meant zero.', wrong: 'Least privilege isn\'t zero privilege. People need access to do their jobs. The principle is minimum NECESSARY, not minimum POSSIBLE.' }, 3: { thought: 'You thought standardization means using one role.', wrong: 'Different people have different jobs. A DBA needs different permissions than a network admin. One role can\'t fit all.' } } },
    { q: 'Which built-in role has full access including the ability to assign roles to others?', choices: ['Reader', 'Contributor', 'Owner', 'User Access Administrator'], answer: 2, explain: 'Owner = full access to all resources AND can manage RBAC assignments. It\'s the most powerful built-in role.', traps: { 0: { thought: 'Nobody picks Reader here. If you did, re-read the question.', wrong: 'Reader can only view resources. No modifications, no deletions, definitely no role assignments.' }, 1: { thought: 'You thought Contributor has full access.', wrong: 'Contributor can create and manage all resources BUT cannot assign roles to others. That\'s the key difference from Owner.' }, 3: { thought: 'You thought User Access Administrator sounds like the role assignment role.', wrong: 'User Access Administrator CAN manage role assignments but doesn\'t have full access to resources themselves. Owner has BOTH.' } } },
    { q: 'What is a custom role in Azure RBAC?', choices: ['A renamed built-in role', 'A role with specific permissions you define', 'A role that only works in one region', 'An Entra ID admin role'], answer: 1, explain: 'Custom roles let you define exactly which permissions (actions) to include. Useful when built-in roles are too broad or too narrow.', traps: { 0: { thought: 'You thought custom just means you change the name.', wrong: 'Custom roles have custom PERMISSIONS, not just custom names. You define which Azure actions are allowed/denied.' }, 2: { thought: 'You confused role scope with regional scope.', wrong: 'Custom roles can be assigned at any scope. The "custom" part is about the permissions, not the geographic scope.' }, 3: { thought: 'You confused Azure RBAC with Entra ID roles.', wrong: 'Azure RBAC custom roles manage Azure resource permissions. Entra ID custom roles manage directory-level permissions. Different systems.' } } },
    { q: 'If Alice has Reader at the subscription level and Contributor on a specific resource group, what happens?', choices: ['Contributor is blocked because Reader was assigned first', 'She has Contributor on that RG and Reader on everything else', 'The roles conflict and she gets no access', 'She gets Owner since both roles combine'], answer: 1, explain: 'RBAC is additive. Roles don\'t conflict or override — they combine. She gets Contributor permissions on that RG and Reader on the rest of the subscription.', traps: { 0: { thought: 'You thought the first-assigned role takes priority.', wrong: 'RBAC doesn\'t have a "first wins" rule. All assignments are evaluated together. More permissive wins at each scope.' }, 2: { thought: 'You thought conflicting scopes create a deadlock.', wrong: 'There is no conflict. Roles are ADDITIVE in Azure. Multiple assignments are combined — the most permissive applies.' }, 3: { thought: 'You thought roles mathematically combine into something higher.', wrong: 'Reader + Contributor ≠ Owner. Each role grants specific permissions. Combining them gives you the union of permissions, not an upgrade to a higher role.' } } },
  ],

  'cost': [
    { q: 'Cloud computing shifts spending from CapEx to...', choices: ['More CapEx', 'OpEx', 'No spending', 'Depreciation'], answer: 1, explain: 'OpEx (operational expenditure) = pay as you go. No upfront hardware purchase. You rent compute by the hour/second instead of buying servers.', traps: { 0: { thought: 'You thought cloud still involves buying hardware.', wrong: 'Cloud eliminates hardware purchases. You don\'t buy servers — you rent them. That shifts spending from capital to operational.' }, 2: { thought: 'You thought cloud means everything is free.', wrong: 'Cloud isn\'t free. You still pay — just differently. Monthly bills instead of upfront hardware costs.' }, 3: { thought: 'You brought in accounting terms that don\'t apply here.', wrong: 'Depreciation applies to owned assets. In cloud, you don\'t own the hardware, so there\'s nothing to depreciate.' } } },
    { q: 'Reserved instances save money by committing to...', choices: ['Pay-as-you-go pricing', '1 or 3 years of usage', '1 month at a time', 'Spot pricing'], answer: 1, explain: '1-year reservation saves ~37%, 3-year saves ~60%. You commit to a specific VM size in a specific region for that duration.', traps: { 0: { thought: 'You confused the question — reserved instances are the ALTERNATIVE to pay-as-you-go.', wrong: 'Pay-as-you-go is the baseline pricing. Reservations are the discount for committing long-term.' }, 2: { thought: 'You thought Azure might offer short-term commitments.', wrong: 'One month isn\'t enough commitment for Azure to offer a discount. The savings come from guaranteed long-term revenue for Microsoft.' }, 3: { thought: 'You confused reserved instances with spot instances.', wrong: 'Spot pricing = cheap but can be interrupted anytime. Reserved = guaranteed capacity with a discount. Opposite concepts.' } } },
    { q: 'The TCO calculator helps estimate savings from...', choices: ['Buying new on-prem hardware', 'Migrating to Azure from on-premises', 'Choosing between Azure services', 'Negotiating enterprise agreements'], answer: 1, explain: 'TCO (Total Cost of Ownership) calculator compares on-prem costs vs Azure. It includes hardware, software, labor, electricity, datacenter space.', traps: { 0: { thought: 'You thought TCO helps with on-prem purchasing decisions.', wrong: 'TCO calculator is a migration tool. It\'s designed to show you how much you\'d SAVE by moving to Azure, not help you buy hardware.' }, 2: { thought: 'You confused TCO calculator with the Pricing calculator.', wrong: 'Pricing calculator estimates Azure service costs. TCO calculator compares on-prem total cost vs Azure total cost. Different tools.' }, 3: { thought: 'You thought TCO is a sales negotiation tool.', wrong: 'TCO is a self-service estimation tool. Enterprise agreement negotiation is done through Microsoft sales.' } } },
    { q: 'Which factor does NOT affect Azure VM pricing?', choices: ['VM size (CPU/RAM)', 'Azure region', 'Resource group name', 'Operating system'], answer: 2, explain: 'Resource group names are just labels. They have zero impact on pricing. VM cost depends on size, region, OS, and disk type.', traps: { 0: { thought: 'You thought maybe simpler VM sizes have different pricing structures.', wrong: 'VM size absolutely affects pricing. More cores and RAM = higher cost. That\'s a real factor.' }, 1: { thought: 'You thought Azure pricing is the same everywhere.', wrong: 'Region significantly affects pricing. East US is often cheaper than West Europe. Energy costs, demand, and local regulations vary.' }, 3: { thought: 'You thought Linux and Windows VMs cost the same.', wrong: 'Windows VMs typically cost more because they include the Windows Server license. Linux is open-source so no license surcharge.' } } },
    { q: 'Azure Cost Management allows you to...', choices: ['Get free Azure credits', 'Set budgets and alerts for spending', 'Reduce SLA requirements', 'Transfer costs to another tenant'], answer: 1, explain: 'Cost Management lets you monitor spending, set budget thresholds, create alerts, and analyze where money is going.', traps: { 0: { thought: 'You thought Cost Management includes free credits.', wrong: 'Cost Management is a monitoring and governance tool. It doesn\'t give you money — it helps you track where it goes.' }, 2: { thought: 'You confused cost management with SLA management.', wrong: 'SLAs and costs are separate concerns. Lowering your SLA requirement doesn\'t reduce costs (if anything, lower redundancy is cheaper but that\'s not what Cost Management does).' }, 3: { thought: 'You thought you could move charges between accounts.', wrong: 'Cost Management doesn\'t transfer billing. It monitors and alerts. Billing transfers involve subscription ownership changes.' } } },
    { q: 'Spot VMs are cheap because...', choices: ['They\'re older hardware', 'Azure can evict them when it needs the capacity back', 'They have no SLA', 'They run slower'], answer: 1, explain: 'Spot VMs use Azure\'s spare capacity at up to 90% discount. The catch: Azure can reclaim them with 30 seconds notice when demand spikes.', traps: { 0: { thought: 'You thought cheap means old.', wrong: 'Spot VMs run on the same hardware as regular VMs. The discount comes from the eviction risk, not hardware quality.' }, 2: { thought: 'You thought "no SLA" is the reason they\'re cheap.', wrong: 'Spot VMs indeed have no SLA, but that\'s a CONSEQUENCE of being evictable, not the reason they\'re cheap. The eviction risk is the core tradeoff.' }, 3: { thought: 'You thought there must be a performance penalty.', wrong: 'Same performance as regular VMs. Identical hardware, identical speed. The only difference is Azure can take it back.' } } },
  ],

  'sla': [
    { q: '99.99% uptime means roughly how much downtime per year?', choices: ['~5 minutes', '~52 minutes', '~8.7 hours', '~36.5 days'], answer: 1, explain: '99.99% = "four nines" = ~52 minutes downtime per year. Each additional nine makes a massive difference.', traps: { 0: { thought: 'You thought four nines means almost zero downtime.', wrong: '5 minutes is closer to five nines (99.999%). Four nines allows nearly an hour of downtime per year.' }, 2: { thought: 'You miscounted the nines. 8.7 hours is three nines (99.9%).', wrong: '99.9% = 8.7 hours/year. 99.99% = 52 minutes/year. Each additional 9 roughly divides downtime by 10.' }, 3: { thought: 'You badly miscounted. 36.5 days is 90% uptime.', wrong: '90% uptime would mean ~36 days of downtime. That would be unusable for any serious service.' } } },
    { q: 'Combining two 99.9% SLA services gives a composite SLA of...', choices: ['99.9%', '99.99%', '99.8%', '99.95%'], answer: 2, explain: '0.999 x 0.999 = 0.998001 = 99.8%. Composite SLAs are always LOWER than any individual SLA. Multiply, don\'t add.', traps: { 0: { thought: 'You thought services in series keep the same SLA.', wrong: 'If either service fails, the whole system fails. Two points of failure = lower combined reliability. It\'s multiplication, not equality.' }, 1: { thought: 'You thought combining services somehow improves reliability.', wrong: 'More components in a chain = MORE failure points = LOWER composite SLA. Adding redundancy improves it, but chaining dependencies worsens it.' }, 3: { thought: 'You averaged instead of multiplied.', wrong: 'SLAs are multiplied, not averaged. The average of 99.9% and 99.9% is 99.9%, but the composite is 99.8%. Math doesn\'t care about your intuition here.' } } },
    { q: 'Adding redundancy to a service can...', choices: ['Lower the SLA', 'Increase the composite SLA', 'Has no effect on SLA', 'Void the SLA guarantee'], answer: 1, explain: 'Redundancy means if one fails, the other takes over. For two redundant paths: 1 - (1 - 0.999) x (1 - 0.999) = 99.9999%. Redundancy dramatically increases composite SLA.', traps: { 0: { thought: 'You thought more components always means lower reliability.', wrong: 'That\'s true for services IN SERIES (chained). Redundancy is PARALLEL — both must fail for the system to fail. That\'s a much lower probability.' }, 2: { thought: 'You thought redundancy is just for disaster recovery, not SLA.', wrong: 'Redundancy directly improves your composite SLA calculation. Running across availability zones, for example, upgrades a VM from 99.9% to 99.99%.' }, 3: { thought: 'You thought adding your own redundancy invalidates Microsoft\'s guarantee.', wrong: 'Your architecture doesn\'t void Microsoft\'s SLA. It improves your overall uptime beyond what one instance guarantees.' } } },
    { q: 'What happens if Azure fails to meet an SLA?', choices: ['Automatic refund of all charges', 'You get service credits (partial refund) if you file a claim', 'Nothing — SLAs are just targets', 'Azure migrates your resources for free'], answer: 1, explain: 'You get service credits (percentage off future bills) but YOU must file a claim. It\'s not automatic, and it\'s credits — not cash refunds.', traps: { 0: { thought: 'You thought Microsoft would automatically refund you.', wrong: 'No cloud provider auto-refunds SLA violations. You must detect the outage, document it, and submit a claim within the deadline.' }, 2: { thought: 'You thought SLAs are aspirational, not contractual.', wrong: 'Azure SLAs are legal commitments with financial consequences. They\'re in the service agreement, not a marketing brochure.' }, 3: { thought: 'You thought Azure would proactively fix things for you.', wrong: 'Azure will fix the underlying issue, but they don\'t migrate your resources or make architectural changes for you. Credits are the compensation.' } } },
    { q: 'Azure Free Tier services have an SLA of...', choices: ['99.99%', '99.9%', '0% — no SLA', '50%'], answer: 2, explain: 'Free tier services come with zero SLA. No guarantee of uptime. You get what you pay for. Want an SLA? Pay for a tier that includes one.', traps: { 0: { thought: 'You thought all Azure services have the same SLA.', wrong: 'SLAs vary by service AND by tier. Free and Basic tiers often have no SLA at all.' }, 1: { thought: 'You thought free tier at least has a basic SLA.', wrong: 'Free means no financial commitment from you and no availability commitment from Azure. It\'s mutual.' }, 3: { thought: 'You thought there might be a reduced SLA.', wrong: 'There\'s no such thing as a 50% SLA. It\'s either a specific high number (99.9%+) or 0%. Azure doesn\'t promise to be up half the time.' } } },
    { q: 'Deploying a VM across availability zones changes its SLA from 99.9% to...', choices: ['99%', '99.9% (no change)', '99.95%', '99.99%'], answer: 3, explain: 'Single VM = 99.9%. Multiple VMs across availability zones = 99.99%. That\'s the incentive for designing with AZ redundancy.', traps: { 0: { thought: 'You thought spreading across zones somehow reduces reliability.', wrong: 'More zones = more fault tolerance. Each zone is independent, so all would need to fail simultaneously.' }, 1: { thought: 'You thought the SLA stays the same regardless of architecture.', wrong: 'Microsoft explicitly offers higher SLAs for zone-redundant deployments. Your architecture directly impacts your SLA.' }, 2: { thought: 'You confused this with Availability Sets, which give 99.95%.', wrong: 'Close! Availability Sets = 99.95%. Availability ZONES = 99.99%. Zones provide better isolation so they get a higher SLA.' } } },
  ],

  'governance': [
    { q: 'A "CanNotDelete" lock prevents...', choices: ['Reading the resource', 'Deleting the resource', 'Modifying the resource', 'Moving the resource'], answer: 1, explain: 'CanNotDelete = you can read and modify, just can\'t delete. It\'s the safety net against "oops I deleted production."', traps: { 0: { thought: 'You thought the lock restricts all access.', wrong: 'CanNotDelete only prevents deletion. Reading and modifying are completely unaffected.' }, 2: { thought: 'You confused CanNotDelete with ReadOnly.', wrong: 'ReadOnly prevents modifications AND deletion. CanNotDelete only prevents deletion. Know the difference — it\'s a common exam question.' }, 3: { thought: 'You thought the lock prevents moving resources between groups.', wrong: 'Moving a resource effectively deletes it from one group and creates it in another — so yes, CanNotDelete blocks moves too. But the primary purpose is preventing deletion.' } } },
    { q: 'Azure Policy can automatically...', choices: ['Delete non-compliant resources', 'Audit or deny non-compliant deployments', 'Create resources that are missing', 'Override RBAC permissions'], answer: 1, explain: 'Azure Policy evaluates deployments against rules. It can audit (report) or deny (block) non-compliant resources. Some policies can also remediate (fix) existing resources.', traps: { 0: { thought: 'You thought Policy would clean up violations by deleting them.', wrong: 'Policy doesn\'t delete resources. That would be destructive and dangerous. It blocks new non-compliant deployments or reports existing violations.' }, 2: { thought: 'You thought Policy could auto-create missing resources.', wrong: 'Policy can deploy remediation tasks (like adding a missing tag), but it doesn\'t create arbitrary resources from scratch.' }, 3: { thought: 'You thought Policy could change access controls.', wrong: 'Policy and RBAC are separate systems. Policy governs WHAT can be deployed. RBAC governs WHO can do things. They don\'t override each other.' } } },
    { q: 'Tags are used for...', choices: ['Security access control', 'Organizing resources and tracking costs', 'Encrypting data', 'Configuring networking'], answer: 1, explain: 'Tags are key-value labels. Use them to categorize resources by department, environment, project — then filter billing reports by those tags.', traps: { 0: { thought: 'You thought tags control who can access resources.', wrong: 'Tags are metadata labels, not access controls. RBAC handles access. Tags help you organize and report.' }, 2: { thought: 'You confused tags with encryption settings.', wrong: 'Tags have nothing to do with encryption. They\'re organizational labels like "env: production" or "team: backend."' }, 3: { thought: 'You thought tags configure resource behavior.', wrong: 'Tags don\'t change how a resource works. They\'re purely for organization, cost tracking, and automation. A tag won\'t change a VM\'s network config.' } } },
    { q: 'ReadOnly lock allows which action?', choices: ['Modify resource configuration', 'Delete the resource', 'Read resource properties only', 'Scale the resource up'], answer: 2, explain: 'ReadOnly = view only. No modifications, no deletions, no scaling. The resource is frozen in its current state.', traps: { 0: { thought: 'You thought "ReadOnly" still allows safe modifications.', wrong: 'ReadOnly means exactly what it says. No writes. No changes. Period.' }, 1: { thought: 'You thought ReadOnly blocks only reads, not writes.', wrong: 'You read the name backwards. ReadOnly means you can ONLY read. Everything else is blocked.' }, 3: { thought: 'You thought scaling is different from modifying.', wrong: 'Scaling changes the resource configuration (size, count). That\'s a modification. ReadOnly blocks it.' } } },
    { q: 'Azure Blueprints are used to...', choices: ['Design UI mockups', 'Define a repeatable set of Azure resources and policies', 'Create network diagrams', 'Backup resource configurations'], answer: 1, explain: 'Blueprints package ARM templates, policies, RBAC assignments, and resource groups into a deployable definition. Stamp out compliant environments repeatedly.', traps: { 0: { thought: 'You took "blueprints" literally as design drawings.', wrong: 'Azure Blueprints aren\'t visual designs. They\'re deployment templates that bundle resources, policies, and access controls together.' }, 2: { thought: 'You thought blueprints are diagrams of your network.', wrong: 'Network diagrams are in Azure Monitor or third-party tools. Blueprints are deployment automation.' }, 3: { thought: 'You confused blueprints with Azure Backup.', wrong: 'Backup saves data. Blueprints define infrastructure as code — what should be deployed and how it should be configured.' } } },
    { q: 'Which governance tool would you use to PREVENT someone from deploying VMs in an unauthorized region?', choices: ['Resource Tags', 'Resource Locks', 'Azure Policy', 'Azure Monitor'], answer: 2, explain: 'Azure Policy with an "Allowed locations" policy. It evaluates every deployment and denies resources in non-approved regions before they\'re created.', traps: { 0: { thought: 'You thought tagging regions could restrict deployments.', wrong: 'Tags are labels. They don\'t enforce anything. You can tag a resource "region: approved" but that doesn\'t prevent deploying elsewhere.' }, 1: { thought: 'You thought locks prevent unauthorized changes.', wrong: 'Locks prevent deletion/modification of EXISTING resources. They don\'t control WHERE new resources are created.' }, 3: { thought: 'You thought monitoring could block bad deployments.', wrong: 'Azure Monitor observes and alerts. It doesn\'t prevent actions. By the time Monitor reports it, the VM is already deployed.' } } },
  ],
}
